<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>WastedToken Mint</title>
    <style>
        body {
            margin: 0;
            padding: 0;
            background-color: #000;
        }

        canvas {
            display: block;
            width: 100%;
            height: 100vh;
        }

        .hero-container {
            position: relative;
            z-index: 10;
        }

        .coin {
            position: absolute;
            top: 0;
            left: 0;
            width: 200px;
            height: 200px;
            background-color: rgba(255, 255, 255, 0.1);
            border-radius: 50%;
            transform-origin: bottom center;
        }

        .coin::after {
            content: "";
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background-color: rgba(255, 255, 255, 0.1);
            border-radius: 50%;
        }

        .coin-front {
            transform: rotateY(-90deg) translateX(10px);
            transform-origin: bottom center;
            box-shadow: 
                inset 5px 5px 15px rgba(255, 255, 255, 0.1),
                0 0 20px rgba(0, 0, 0, 0.2);
        }

        .coin-back {
            transform: rotateY(90deg) translateX(-10px);
            transform-origin: bottom center;
            box-shadow: 
                inset 5px 5px 15px rgba(255, 255, 255, 0.1),
                0 0 20px rgba(0, 0, 0, 0.2);
        }

        .coin-front::after {
            content: "";
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            border-radius: 50%;
        }

        .coin-back::after {
            content: "";
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            border-radius: 50%;
        }

        .edition {
            display: inline-block;
            margin-bottom: 10px;
            padding: 5px;
            background-color: rgba(255, 255, 255, 0.2);
            border-radius: 8px;
            font-weight: bold;
        }

        .available {
            color: #00ff00;
        }

        .sold-out {
            color: #ff0000;
        }

        .coming-soon {
            color: #00ffff;
        }
    </style>
</head>
<body>
    <div class="hero-container">
        <div class="coin" id="coin"></div>
    </div>

    <script>
        // Hero canvas
        const heroCanvas = document.getElementById('coin-hero');

        // Coin geometry (3D object)
        const coinGeometry = new THREE.Cube();
        coinGeometry.position.set(-50, -100, 0);
        coinGeometry.size.set(200, 200, 150);
        coinGeometry.color.set(0x0000FF); // white

        // Transformation matrix for rotation about vertical axis (y-axis) and flip horizontally
        const transform = new THREE.Matrix4();
        transform.translate(-50, -100);
        transform.rotateY(90); // rotate around y-axis by 90 degrees -> flips left-right

        coinGeometry.matrix.set(transform);

        // Material for coin with metallic finish and specular highlight
        const coinMaterial = new THREE.MeshBasicMaterial({
            color: 0x0000FF,
            roughness: 10, // metallic finish
            highlight: 5,   // specular highlight radius
            transparent: true
        });

        // Create coin mesh
        const coinMesh = new THREE.Mesh(coinGeometry, coinMaterial);
        coinMesh.position.set(-50, -100, 0); // position inside canvas

        // Add coin to scene (for demonstration)
        const scene = new THREE.Scene();
        scene.background.color.set(0x0000FF);
        scene.orthographicCamera.front = { x: -1, y: 0, z: 0 };
        scene.orthographicCamera.back = { x: 1, y: 0, z: 0 };

        // Add coin to scene
        scene.add(coinMesh);

        // Animation loop (setTime)
        function setTime(t) {
            // Rotate coin about vertical axis by 90 degrees (y-axis rotation)
            coinMesh.rotation.y += t * 0.1; // rotate around y-axis

            // Flip coin horizontally (rotate around x-axis by 180 degrees)
            transform.set(transform.translate(-50, -100));
            transform.rotateX(180);
        }

        // Pause animation
        window.demo.pause = () => {
            setTimeout(() => {
                heroCanvas.style.display = 'none';
            }, 2000);
        };
    </script>
</body>
</html>
